15	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
16	  it.todo("should bring a dead cell with exactly 3 neighbors alive (reproduction)");
17	  it.todo("should transform a vertical blinker to a horizontal blinker (oscillator)");
18	});
