1	export function nextGeneration(grid: boolean[][]): boolean[][] {
2	  return grid.map((row) => {
3	    const isUnderpopulated = row.length <= 1;
4	    return isUnderpopulated ? [] : row.map(() => false);
5	  });
6	}
